INSERT INTO `Courses` (`Uuid`, `Name`, `Description`, `ImageUrl`, `Status`, `ScheduledStart`, `ViewCount`, `LecturerUuid`, `CategoryUuid`, `OrganizationUuid`, `UpdatedAt`, `CreatedAt`) VALUES
('008eecac-40eb-4882-8fd3-7ae2ab7cd829', 'Čtení dokumentace bez frustrace', 'Čtení dokumentace bez frustrace je kurz zaměřený na praktické zvládnutí tématu. Cílem kurzu je dát jistotu v základních i pokročilejších situacích. Kombinuje krátký výklad, samostatné úkoly a praktické checklisty. Zaměříme se hlavně na Tech English, Čtení dokumentace, E-maily a na konci budeš mít konkrétní výstup do portfolia nebo praxe.', NULL, 4, NULL, 6796, '926318c3-d6c1-4a07-aab5-078902f6b9cb', 'be1a4509-284a-4374-8003-9e21e47d5d26', '00000000-0000-0000-0000-000000000000', '2026-02-04 15:33:22.194883', '2026-01-08 02:27:21.464632'),
